import React from 'react';
import './Sidebar.css';
import { Home, Folder, Users, Moon, Sparkles, Settings } from 'lucide-react';
import figarooLogo from '../public/figaroo-logo.png';

const Sidebar: React.FC = () => {
  return (
    <div className="sidebar">
      {/* Logo */}
      <div className="logo">
        <img src={figarooLogo} alt="Figaroo Logo" className="figaroo-logo-img" />
      </div>

      {/* User Profile */}
      <div className="user-profile">
        <div className="user-avatar">
          <Sparkles size={16} />
        </div>
        <span className="user-name">Ali Shan</span>
        <button className="dropdown-btn">▼</button>
      </div>

      {/* Navigation */}
      <nav className="nav">
        <a href="#" className="nav-item active">
          <Home className="nav-icon" size={18} />
          <span>Home</span>
        </a>
        <a href="#" className="nav-item">
          <Folder className="nav-icon" size={18} />
          <span>My Files</span>
        </a>
        <a href="#" className="nav-item">
          <Users className="nav-icon" size={18} />
          <span>Shared with Me</span>
        </a>
        <a href="#" className="nav-item">
          <Settings className="nav-icon" size={18} />
          <span>Settings</span>
        </a>
      </nav>

      {/* Components Counter */}
      <div className="components-counter">
        <div className="counter-bar">
          <div className="counter-fill" style={{ width: '60%' }}></div>
        </div>
        <span className="counter-text">3/5 Components used</span>
      </div>

      {/* Theme Toggle */}
      <button className="theme-toggle" title="Toggle Theme">
        <Moon size={18} />
      </button>
    </div>
  );
};

export default Sidebar;
